import React from "react"
import { Link } from "gatsby"
import Img from "gatsby-image"
import PropTypes from "prop-types"

const Post = ({ id, fields, excerpt, frontmatter }) => {
  return (
    <div className="bg-white max-w-img m-2 rounded shadow-xl hover:shadow-inner">
      <Link to={fields.slug}>
        <Img
          fixed={frontmatter.coverImage.childImageSharp.fixed}
          className="rounded"
          alt="Cover Image"
        />
        <div className="px-4 py-6">
          <div className="mb-2 font-bold text-lg text-center">
            {frontmatter.title}
          </div>
          <p className="text-gray-700 text-base text-justify">{excerpt}</p>
        </div>
      </Link>

      <div className="flex flex-wrap content-center justify-end px-4 py-6">
        {frontmatter.tags.map((item, index) => (
          <span
            key={`${id}+${index}`}
            className="cursor-pointer inline-block bg-gray-200 rounded-full px-3 py-1 text-sm font-semibold text-gray-700 mr-2"
          >
            {item}
          </span>
        ))}
      </div>
    </div>
  )
}

Post.propTypes = {
  id: PropTypes.string.isRequired,
  excerpt: PropTypes.string.isRequired,
  fields: PropTypes.shape({
    slug: PropTypes.string.isRequired
  }).isRequired,
  frontmatter: PropTypes.shape({
    date: PropTypes.string,
    title: PropTypes.string
  }).isRequired
}

export default Post
