import React from "react"
import { graphql } from "gatsby"

import SEO from "../components/seo"
import Post from "./../components/post"
import Layout from "../components/layout"

const Blog = ({ data }) => {
  const { edges } = data.allMarkdownRemark

  return (
    <Layout>
      <SEO title="Blog" />
      <div className="h-full flex flex-col items-center justify-start sm:flex-row sm:items-start">
        {edges.map(({ node }) => (
          <Post key={`${node.frontmatter.title}`} {...node} />
        ))}
      </div>
    </Layout>
  )
}

export default Blog

// default query to populate list
export const query = graphql`
  query {
    allMarkdownRemark(
      sort: { fields: [frontmatter___date], order: DESC }
      filter: { frontmatter: { draft: { ne: true } } }
    ) {
      totalCount
      edges {
        node {
          id
          excerpt
          fields {
            slug
          }
          frontmatter {
            tags
            title
            date(formatString: "MMMM DD, YYYY")
            coverImage {
              childImageSharp {
                fixed(width: 300) {
                  ...GatsbyImageSharpFixed
                }
              }
            }
          }
        }
      }
    }
  }
`
